props.onChangeCodeToExecute:
{{ (() => {
    console.log("on value change")
    const value = event.target.value;

    if (value.length >= 3) {
      const filteredHotels = allHotels.filter(hotel =>  hotel.hotelName.toLowerCase().includes(value.toLowerCase()));
      actions.updateVariable("hotels", filteredHotels);
    }
    if (value.length === 0) {
      actions.updateVariable("hotels", allHotels);
    }
  })()
}}
